example.code:
variables {
message 0x100 msg;
}
on start
{
msg.CAN = 1;
msg.DLC = 0;
}
on key 'w' 
{
// sets the transceiver of channel 1 in HighVoltage mode 
// and the transceiver of channel 2 in Normal mode.
setPortBits(0x0D);
// sends the message.
output(msg);

// After sending the Wakeup message the transceiver
// of both channels will be set to Normal mode.
setPortBits(0x0F);
}
on message *
{
output(this);
}
